#!/usr/bin/env python3
"""
🏀 Curry Alerts — Steph Curry-themed Claude Code hook notifications.

Each Claude Code session event triggers a humorous Steph Curry alert:
macOS notification, optional sound, optional YouTube video.

Usage (via hooks):   python3 curry_alerts.py <EventName>
Customize:          edit curry.config.json
Install hooks:      python3 install.py
"""

import sys
import os
import json
import random
import subprocess
from pathlib import Path

SCRIPT_DIR = Path(__file__).parent.resolve()
CONFIG_PATH = SCRIPT_DIR / "curry.config.json"

# ── Read stdin BEFORE self-detaching (Claude Code passes JSON event data) ────
_stdin_data: dict = {}
if not os.environ.get("CURRY_DETACHED"):
    try:
        raw = sys.stdin.read(4096)
        if raw.strip():
            _stdin_data = json.loads(raw)
    except Exception:
        pass

_tool_name = _stdin_data.get("tool_name", os.environ.get("CURRY_TOOL", ""))
_notif_msg = _stdin_data.get("message",   os.environ.get("CURRY_MSG",  ""))

# ── Self-detach so the hook returns immediately ──────────────────────────────
if not os.environ.get("CURRY_DETACHED"):
    subprocess.Popen(
        [sys.executable, __file__] + sys.argv[1:],
        env={**os.environ,
             "CURRY_DETACHED": "1",
             "CURRY_TOOL": _tool_name,
             "CURRY_MSG":  _notif_msg},
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        start_new_session=True,
    )
    sys.exit(0)

# ─────────────────────────────────────────────────────────────────────────────
# Everything below runs only in the detached child.
# ─────────────────────────────────────────────────────────────────────────────

def _load_config() -> dict:
    if CONFIG_PATH.exists():
        with open(CONFIG_PATH) as f:
            return json.load(f)
    return {}


def _notify(title: str, body: str) -> None:
    """Fire a macOS notification and also echo to stderr (shows in CC logs)."""
    t = title.replace('"', '\\"').replace("'", "'")
    b = body.replace('"',  '\\"').replace("'", "'")
    try:
        subprocess.run(
            ["osascript", "-e", f'display notification "{b}" with title "{t}"'],
            capture_output=True, timeout=4,
        )
    except Exception:
        pass
    print(f"🏀  {title} — {body}", file=sys.stderr)


def _play_sound(path: str | None) -> None:
    if not path:
        return
    p = Path(path)
    if not p.is_absolute():
        p = SCRIPT_DIR / p
    if p.exists():
        subprocess.Popen(["afplay", str(p)],
                         stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)


def _open_video(url: str | None) -> None:
    if not url:
        return
    subprocess.Popen(["open", url],
                     stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)


def _tool_bucket(tool: str) -> str:
    """Map a raw tool name to one of the config bucket keys."""
    tool = tool.lower()
    if any(t in tool for t in ("write", "edit", "multiedit", "notebook")):
        return "Write"
    if "bash" in tool:
        return "Bash"
    if any(t in tool for t in ("read", "glob", "grep")):
        return "Read"
    if any(t in tool for t in ("web", "search", "fetch")):
        return "Web"
    return "Other"


def handle(event: str, tool_name: str = "", notif_msg: str = "") -> None:
    cfg    = _load_config()
    events = cfg.get("events", {})

    # Build lookup order: specific bucket → generic event fallback
    keys = [event]
    if event == "PreToolUse" and tool_name:
        keys.insert(0, f"PreToolUse_{_tool_bucket(tool_name)}")
    if event == "Notification" and "permission" in notif_msg.lower():
        keys.insert(0, "Notification_Permission")

    event_cfg: dict = {}
    for k in keys:
        if k in events:
            event_cfg = events[k]
            break

    if not event_cfg.get("enabled", True):
        return

    # Probability gate (0.0–1.0, default 1.0)
    if random.random() > event_cfg.get("probability", 1.0):
        return

    messages = event_cfg.get("messages", [])
    if not messages:
        return

    title = event_cfg.get("title", "🏀 Curry Alert")
    body  = random.choice(messages)

    # Substitute {tool} or {message} placeholders if present
    body  = body.replace("{tool}", tool_name).replace("{message}", notif_msg)

    _notify(title, body)
    _play_sound(event_cfg.get("sound"))
    _open_video(event_cfg.get("video_url"))


if __name__ == "__main__":
    event     = sys.argv[1] if len(sys.argv) > 1 else "Unknown"
    tool_name = _tool_name
    notif_msg = _notif_msg
    handle(event, tool_name, notif_msg)

#!/usr/bin/env python3
"""
Install / uninstall Curry Alerts hooks into Claude Code settings.

  python3 install.py            # install into ~/.claude/settings.json
  python3 install.py --project  # install into ./.claude/settings.json
  python3 install.py --uninstall
"""

import sys
import json
import shutil
from pathlib import Path

SCRIPT_PATH = Path(__file__).parent.resolve() / "curry_alerts.py"
PY          = sys.executable
CMD         = lambda event: f"{PY} {SCRIPT_PATH} {event}"

# Hooks to install — order matters within each event array.
CURRY_HOOKS = {
    "UserPromptSubmit": [
        {"hooks": [{"type": "command", "command": CMD("UserPromptSubmit")}]}
    ],
    "PreToolUse": [
        {
            "matcher": "Write|Edit|MultiEdit|NotebookEdit",
            "hooks": [{"type": "command", "command": CMD("PreToolUse")}],
        },
        {
            "matcher": "Bash",
            "hooks": [{"type": "command", "command": CMD("PreToolUse")}],
        },
        {
            "matcher": "Read|Glob|Grep",
            "hooks": [{"type": "command", "command": CMD("PreToolUse")}],
        },
        {
            "matcher": "WebSearch|WebFetch",
            "hooks": [{"type": "command", "command": CMD("PreToolUse")}],
        },
    ],
    "Notification": [
        {"hooks": [{"type": "command", "command": CMD("Notification")}]}
    ],
    "Stop": [
        {"hooks": [{"type": "command", "command": CMD("Stop")}]}
    ],
}


def _load(path: Path) -> dict:
    if path.exists():
        try:
            return json.loads(path.read_text())
        except json.JSONDecodeError:
            print(f"⚠️  {path} contains invalid JSON — creating backup and starting fresh.")
            shutil.copy(path, path.with_suffix(".bak.json"))
    return {}


def _save(path: Path, data: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2) + "\n")


def _is_curry_cmd(cmd: str) -> bool:
    return "curry_alerts.py" in cmd


def install(settings_path: Path) -> None:
    cfg = _load(settings_path)
    hooks = cfg.setdefault("hooks", {})

    added = 0
    for event, new_entries in CURRY_HOOKS.items():
        bucket = hooks.setdefault(event, [])

        # Remove any stale Curry entries first (re-install idempotently)
        before = len(bucket)
        bucket[:] = [
            entry for entry in bucket
            if not any(
                _is_curry_cmd(h.get("command", ""))
                for h in entry.get("hooks", [])
            )
        ]
        removed = before - len(bucket)
        if removed:
            print(f"  ↺  Replaced {removed} existing Curry hook(s) for {event}")

        bucket.extend(new_entries)
        added += len(new_entries)

    _save(settings_path, cfg)
    print(f"\n✅  Installed {added} hook entries into {settings_path}")
    print(f"    Script: {SCRIPT_PATH}")
    print("\n🏀  Curry Alerts is live. Start a Claude Code session to test it.")
    print("    Customize messages/sounds/videos in curry.config.json\n")


def uninstall(settings_path: Path) -> None:
    if not settings_path.exists():
        print(f"Nothing to uninstall — {settings_path} doesn't exist.")
        return

    cfg   = _load(settings_path)
    hooks = cfg.get("hooks", {})
    total = 0

    for event in list(hooks.keys()):
        before = len(hooks[event])
        hooks[event] = [
            entry for entry in hooks[event]
            if not any(
                _is_curry_cmd(h.get("command", ""))
                for h in entry.get("hooks", [])
            )
        ]
        total += before - len(hooks[event])
        if not hooks[event]:
            del hooks[event]

    _save(settings_path, cfg)
    print(f"🗑️   Removed {total} Curry hook entries from {settings_path}")


def main() -> None:
    args     = sys.argv[1:]
    project  = "--project"  in args
    removing = "--uninstall" in args

    if project:
        target = Path(".claude") / "settings.json"
        scope  = "project"
    else:
        target = Path.home() / ".claude" / "settings.json"
        scope  = "global"

    print(f"{'Uninstalling' if removing else 'Installing'} Curry Alerts ({scope}) → {target}\n")

    if removing:
        uninstall(target)
    else:
        install(target)


if __name__ == "__main__":
    main()

